SELECT organization_name
FROM sponsoring_organizations
WHERE sponsor_id = 0;

SELECT usage_count
FROM research_outputs
WHERE output_id = 0;

SELECT title, citation_count
FROM research_outputs
ORDER BY citation_count DESC;

SELECT title
FROM research_outputs
ORDER BY usage_count DESC, citation_count DESC;

SELECT COUNT(*) AS total_highly_cited_outputs
FROM research_outputs
WHERE citation_count > 10;
